Here's a complete example of data-driven MSTest tests for your `PriceCalculator`:

```csharp
using Microsoft.VisualStudio.TestTools.UnitTesting;

// --- System Under Test ---
public class PriceCalculator
{
    public decimal CalculateTotal(decimal unitPrice, int quantity)
    {
        ArgumentOutOfRangeException.ThrowIfNegative(unitPrice);
        ArgumentOutOfRangeException.ThrowIfNegativeOrZero(quantity);
        return unitPrice * quantity;
    }

    public decimal ApplyDiscount(decimal total, decimal discountPercent)
    {
        ArgumentOutOfRangeException.ThrowIfNegative(total);
        ArgumentOutOfRangeException.ThrowIfNegative(discountPercent);
        ArgumentOutOfRangeException.ThrowIfGreaterThan(discountPercent, 100m);
        return total * (1 - discountPercent / 100m);
    }
}

// --- Tests ---
[TestClass]
public class PriceCalculatorTests
{
    // ═══════════════════════════════════════════
    // DataRow — best for simple inline cases
    // ═══════════════════════════════════════════

    [TestMethod]
    [DataRow(10.00, 1, 10.00, DisplayName = "Single item")]
    [DataRow(10.00, 5, 50.00, DisplayName = "Multiple items")]
    [DataRow(0.99, 3, 2.97, DisplayName = "Fractional price")]
    [DataRow(0.00, 1, 0.00, DisplayName = "Zero price")]
    [DataRow(1000.00, 100, 100_000.00, DisplayName = "Large order")]
    public void CalculateTotal_ReturnsExpectedResult(
        double unitPrice, int quantity, double expected)
    {
        var calculator = new PriceCalculator();

        var result = calculator.CalculateTotal((decimal)unitPrice, quantity);

        Assert.AreEqual((decimal)expected, result);
    }

    [TestMethod]
    [DataRow(100.00, 0.0, 100.00, DisplayName = "No discount")]
    [DataRow(100.00, 10.0, 90.00, DisplayName = "10% off")]
    [DataRow(100.00, 50.0, 50.00, DisplayName = "50% off")]
    [DataRow(100.00, 100.0, 0.00, DisplayName = "100% off (free)")]
    [DataRow(49.99, 25.0, 37.4925, DisplayName = "Fractional result")]
    public void ApplyDiscount_ReturnsExpectedResult(
        double total, double discountPercent, double expected)
    {
        var calculator = new PriceCalculator();

        var result = calculator.ApplyDiscount((decimal)total, (decimal)discountPercent);

        Assert.AreEqual((decimal)expected, result);
    }

    // ═══════════════════════════════════════════
    // DynamicData — best for complex/computed cases
    // ═══════════════════════════════════════════

    public static IEnumerable<object[]> DiscountEdgeCases =>
    [
        [200m, 33.33m, 133.34m, "Repeating decimal discount"],
        [0m, 50m, 0m, "Zero total with discount"],
        [999.99m, 15m, 849.9915m, "Realistic cart scenario"],
    ];

    [TestMethod]
    [DynamicData(nameof(DiscountEdgeCases))]
    public void ApplyDiscount_EdgeCases(
        decimal total, decimal discountPercent, decimal expected, string scenario)
    {
        var calculator = new PriceCalculator();

        var result = calculator.ApplyDiscount(total, discountPercent);

        Assert.AreEqual(expected, result, $"Failed for: {scenario}");
    }

    // DynamicData from a method (useful when data needs computation)
    public static IEnumerable<object[]> GetBulkOrderCases()
    {
        var prices = new[] { 5.00m, 19.99m, 149.95m };
        var quantities = new[] { 1, 10, 50 };

        foreach (var price in prices)
            foreach (var qty in quantities)
                yield return [price, qty, price * qty];
    }

    [TestMethod]
    [DynamicData(nameof(GetBulkOrderCases), DynamicDataSourceType.Method)]
    public void CalculateTotal_BulkOrders(
        decimal unitPrice, int quantity, decimal expected)
    {
        var calculator = new PriceCalculator();

        var result = calculator.CalculateTotal(unitPrice, quantity);

        Assert.AreEqual(expected, result);
    }

    // ═══════════════════════════════════════════
    // Negative / exception tests with DataRow
    // ═══════════════════════════════════════════

    [TestMethod]
    [DataRow(-1.00, 1, DisplayName = "Negative price")]
    [DataRow(10.00, 0, DisplayName = "Zero quantity")]
    [DataRow(10.00, -5, DisplayName = "Negative quantity")]
    public void CalculateTotal_InvalidInput_Throws(double unitPrice, int quantity)
    {
        var calculator = new PriceCalculator();

        Assert.ThrowsException<ArgumentOutOfRangeException>(
            () => calculator.CalculateTotal((decimal)unitPrice, quantity));
    }

    [TestMethod]
    [DataRow(100.00, -1.0, DisplayName = "Negative discount")]
    [DataRow(100.00, 101.0, DisplayName = "Discount over 100%")]
    [DataRow(-50.00, 10.0, DisplayName = "Negative total")]
    public void ApplyDiscount_InvalidInput_Throws(double total, double discountPercent)
    {
        var calculator = new PriceCalculator();

        Assert.ThrowsException<ArgumentOutOfRangeException>(
            () => calculator.ApplyDiscount((decimal)total, (decimal)discountPercent));
    }
}
```

**Key best practices shown:**

| Technique | When to use |
|-----------|-------------|
| `[DataRow]` | Simple inline values (note: only compile-time constants — use `double` not `decimal`) |
| `[DynamicData]` with property | Complex types or `decimal` literals |
| `[DynamicData]` with method | Computed/combinatorial test data |
| `DisplayName` | Makes Test Explorer output readable |

**Notes:**
- `DataRow` can't use `decimal` directly (not a compile-time constant), so pass `double` and cast in the method.
- `DynamicData` supports `decimal`, complex objects, and generated data.
- Each test follows Arrange/Act/Assert with a single assertion per logical concern.
- Exception tests validate boundary conditions separately from happy-path tests.
